import React, { useMemo } from 'react';
import type { UseVoucherListSelectionResult } from '../../hooks/useVoucherListSelection';
import {
  CatalogListGridFromSchema,
  type CatalogListGridFromSchemaProps,
  listVisibleFields,
  useCatalogUiSchema,
} from '../listUiSchema';
import type { CatalogUiSchema } from '../../types/catalogUiSchema';
import erp from '../../styles/erpPage.module.css';

export type ReportSchemaListGridProps<T extends { id: string }> = {
  catalogKind: string;
  testIdPrefix: string;
  rows: T[];
  page?: number;
  pageSize?: number;
  showTableLoading: boolean;
  emptyLabel: string;
  selection: UseVoucherListSelectionResult<T>;
  onRowDoubleClick?: (row: T) => void;
  sampleRow?: Record<string, unknown> | null;
};

/** Read-only report grid — `ErpDataListGrid` + ui-schema (Zone F). */
export function ReportSchemaListGrid<T extends { id: string }>({
  catalogKind,
  testIdPrefix,
  rows,
  page = 1,
  pageSize = rows.length || 20,
  showTableLoading,
  emptyLabel,
  selection,
  onRowDoubleClick,
  sampleRow: sampleRowProp,
}: ReportSchemaListGridProps<T>): React.ReactElement | null {
  const sampleRow = useMemo(
    () => sampleRowProp ?? (rows[0] ? (rows[0] as unknown as Record<string, unknown>) : null),
    [rows, sampleRowProp],
  );
  const { schema } = useCatalogUiSchema(catalogKind, { sampleRow });
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);

  if (!showTableLoading && rows.length === 0) {
    return (
      <div className={erp.empty} data-testid={`${testIdPrefix}-empty`}>
        <i className="fas fa-inbox" />
        <p>{emptyLabel}</p>
      </div>
    );
  }

  if (showTableLoading || listColumns.length === 0) return null;

  const gridProps: CatalogListGridFromSchemaProps<T>['gridProps'] | undefined = onRowDoubleClick
    ? { onRowDoubleClick: (row: T) => onRowDoubleClick(row) }
    : undefined;

  return (
    <CatalogListGridFromSchema<T>
      testIdPrefix={testIdPrefix}
      rows={rows}
      page={page}
      pageSize={pageSize}
      columns={listColumns}
      schema={schema as CatalogUiSchema | null}
      selection={selection}
      getRowId={r => r.id}
      gridProps={gridProps}
    />
  );
}
